#include <stdio.h>
int canPartition(int* nums, int numsSize) {
    int sum = 0;
    for (int i = 0; i < numsSize; i++) {
        sum += nums[i];
    }
    if (sum % 2 != 0) return 0;
    int target = sum / 2;
    int dp[numsSize + 1][target + 1];
    for (int i = 0; i <= numsSize; i++) {
        for (int j = 0; j <= target; j++) {
            if (i == 0 && j == 0) dp[i][j] = 1;
            else if (i == 0) dp[i][j] = 0;
            else if (j < nums[i - 1]) dp[i][j] = dp[i - 1][j];
            else dp[i][j] = dp[i - 1][j] || dp[i - 1][j - nums[i - 1]];
        }
    }
    return dp[numsSize][target];
}

